/**
 * Unit tests for classify-source.ts
 * Tests path-based classification into project / rules / plugin / unknown tiers
 */

import { describe, test, expect } from 'vitest';
import { classifySource } from '../../instructions-loaded/classify-source.js';

describe('classifySource', () => {
  describe('project tier', () => {
    test('classifies root CLAUDE.md as project', () => {
      expect(classifySource('/project/CLAUDE.md')).toBe('project');
    });

    test('classifies CLAUDE.md in subdirectory as project', () => {
      expect(classifySource('/Users/yonatangross/coding/orchestkit/CLAUDE.md')).toBe('project');
    });

    test('does not classify CLAUDE.md inside .claude/ as project', () => {
      // Files under .claude/ are rules, not the top-level project file
      expect(classifySource('/project/.claude/CLAUDE.md')).not.toBe('project');
    });
  });

  describe('rules tier', () => {
    test('classifies .claude/rules/ files as rules', () => {
      expect(classifySource('/project/.claude/rules/antipatterns.md')).toBe('rules');
    });

    test('classifies nested .claude/rules/ path as rules', () => {
      expect(classifySource('/Users/yonatangross/coding/orchestkit/.claude/rules/hooks-development.md')).toBe('rules');
    });

    test('classifies claude/rules/ (no leading dot) as rules', () => {
      expect(classifySource('/project/claude/rules/style-guide.md')).toBe('rules');
    });
  });

  describe('plugin tier', () => {
    test('classifies path containing "plugin" as plugin', () => {
      expect(classifySource('/home/.claude/plugins/cache/orchestkit/ork/7.1.11/SKILL.md')).toBe('plugin');
    });

    test('classifies CLAUDE_PLUGIN path as plugin', () => {
      expect(classifySource('/some/CLAUDE_PLUGIN/instructions.md')).toBe('plugin');
    });
  });

  describe('unknown tier', () => {
    test('classifies unrecognized path as unknown', () => {
      expect(classifySource('/tmp/random-file.md')).toBe('unknown');
    });

    test('classifies empty string as unknown', () => {
      expect(classifySource('')).toBe('unknown');
    });

    test('classifies plain filename without directory as unknown', () => {
      expect(classifySource('instructions.md')).toBe('unknown');
    });
  });
});
